import type { ReactNode } from 'react';
import type { TestComponentProps } from 'src/types/test-component';
/**
 * Размер компонента Copy (наследуется от Link).
 */
export type CopySize = 'large' | 'medium' | 'small';
/**
 * Публичный тип пропсов компонента Copy.
 *
 * @example
 * ```tsx
 * <Copy value="https://example.com">Копировать ссылку</Copy>
 *
 * <Copy value={id} showTooltip={false}>Копировать ID</Copy>
 * ```
 */
export interface CopyProps extends TestComponentProps {
    /**
     * Строка для копирования в буфер обмена.
     */
    value: string;
    /**
     * Текст/контент ссылки.
     */
    children: ReactNode;
    /**
     * Показывать Tooltip.
     * @default true
     */
    showTooltip?: boolean;
    /**
     * Текст Tooltip при ховере (до копирования).
     * @default 'Копировать'
     */
    tooltipText?: string;
    /**
     * Текст Tooltip после копирования.
     * @default 'Скопировано'
     */
    tooltipCopiedText?: string;
    /**
     * Длительность состояния «скопировано» в миллисекундах.
     * @default 3000
     */
    copiedStateDuration?: number;
    /**
     * Размер компонента.
     * @default 'medium'
     */
    size?: CopySize;
    /**
     * Колбэк после успешного копирования.
     */
    onCopy?: (value: string, event: React.MouseEvent<HTMLElement>) => void;
    /**
     * Колбэк при ошибке копирования.
     */
    onCopyError?: (error: Error) => void;
    /**
     * Пользовательский класс.
     */
    className?: string;
}
